const {useEffect} = os.appHooks;

const VoiceAI = ({ start, connected, isAssistantSpeaking, setStart, setMicActive, setSpeakerActive }) => {

    useEffect(() => {
        setMicActive(true);
        setSpeakerActive(true);
    }, [])
    return (
        <div className="voice-container">
            <button
                className={`ai-btn ${!start ? 'disconnected' : connected ? 'connected' : 'connecting'} ${isAssistantSpeaking ? "speaking" : ""}`}
            >
                <svg width="34" height="32" viewBox="0 0 34 32" fill="none" xmlns="http://www.w3.org/2000/svg" xlink="http://www.w3.org/1999/xlink">
                    <rect width="34" height="32" fill="url(#pattern0_3276_2043)" />
                    <defs>
                        <pattern id="pattern0_3276_2043" patternContentUnits="objectBoundingBox" width="1" height="1">
                            <use href="#image0_3276_2043" transform="matrix(0.000919118 0 0 0.000976562 -0.00459559 0)" />
                        </pattern>
                        <image id="image0_3276_2043" width="1098" height="1024" preserveAspectRatio="none" href="data:image/png;base64," />
                    </defs>
                </svg>

            </button>
            {!start ? <p>Disconnected</p> : connected ? <p> Connected</p> : <p> Connecting...</p>}
        </div>
    );
};

export default VoiceAI;